INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), '1sm', 9, 1, NULL, 'Atanásio em 1Sm 9:1', 'Na leitura de Atanásio, vemos a leitura cristológica e eclesial da passagem. 1 Samuel 9 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Atanásio', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), '1sm', 10, 1, NULL, 'Thomas Watson em 1Sm 10:1', 'Segundo Thomas Watson, a piedade prática e a santificação do coração ilumina o sentido deste texto. 1 Samuel 10 mostra que providência divina na história do povo de Deus sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Thomas Watson', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), '1sm', 11, 1, NULL, 'Andrew Murray em 1Sm 11:1', 'Na leitura de Andrew Murray, vemos a coerência doutrinária aplicada à vida cristã. 1 Samuel 11 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Andrew Murray', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), '1sm', 12, 1, NULL, 'Orígenes em 1Sm 12:1', 'Orígenes interpreta este versículo a partir de a leitura cristológica e eclesial da passagem. Em 1 Samuel 12, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Orígenes', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), '1sm', 13, 1, NULL, 'Richard Baxter em 1Sm 13:1', 'Richard Baxter destaca a piedade prática e a santificação do coração. Em 1 Samuel 13, o foco recai sobre providência divina na história do povo de Deus e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Richard Baxter', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), '1sm', 14, 1, NULL, 'Charles Spurgeon em 1Sm 14:1', 'Charles Spurgeon interpreta este versículo a partir de a coerência doutrinária aplicada à vida cristã. Em 1 Samuel 14, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Charles Spurgeon', 'commentary', '#1D4ED8', NOW()),
